import{_ as e,o as a,c as t,ak as _}from"./chunks/framework.BwREiRwV.js";const h=JSON.parse('{"title":"第十八章 第三名与旧伤","description":"","frontmatter":{},"headers":[],"relativePath":"永恒道途/正文/第一卷-山门有路/第十八章-第三名与旧伤.md","filePath":"永恒道途/正文/第一卷-山门有路/第十八章-第三名与旧伤.md"}'),r={name:"永恒道途/正文/第一卷-山门有路/第十八章-第三名与旧伤.md"};function o(n,p,s,c,i,d){return a(),t("div",null,[...p[0]||(p[0]=[_('<h1 id="第十八章-第三名与旧伤" tabindex="-1">第十八章 第三名与旧伤 <a class="header-anchor" href="#第十八章-第三名与旧伤" aria-label="Permalink to &quot;第十八章 第三名与旧伤&quot;">​</a></h1><p>第三日清晨，演武场中央只剩下一座擂台。</p><p>另外七座连夜拆了，青岗岩整齐码在场边，白玉主擂四周则新换了金边青纹旗。负责阵法的执事跪在台角补最后一道纹路，补完还不放心，叫一名弟子上去全力劈了一刀。阵光只晃了晃，他这才收起朱砂笔。</p><p>主峰钟楼提前敲响三声。外门弟子挤在最前，内门弟子占了东侧看台，各峰执事与长老坐得更高。人比前两日少，场边却更安静。能留到今日的五个人，名字早已被许多人抄进了名册。</p><p>陈玄站在候战区，左肩的雷伤只退去麻意，胸口被枪尾击中的位置仍泛着大片青紫。一夜调息让灵力恢复，却没有让伤势好了大半。今日的对手与之前完全不同，他也必须带着前两日积下的代价上台。</p><p>前五之中，除他之外，叶承、秦岚、赵无锋皆是炼气九层，唯有他是炼气七层。境界的差距如同鸿沟，前两日他还能以技巧弥补，但今日面对的，是外门真正的顶尖天才。</p><p>“前五抽签，决定最终名次！”</p><p>执事长老念过赛制，将签筒放在众人面前。</p><p>陈玄伸手入签筒，取出一枚玉签——首战对手：叶承。</p><p>炼气九层，外门公认第一人，据说其实力已不弱于普通内门弟子。</p><p>“有意思。”叶承站在擂台另一端，一袭玄衣，身形修长。他手中握着一对双刃短戟，戟身漆黑如墨，隐隐有幽光流转。</p><p>叶承道：“陈师弟，我看过你的比试。韩牧守得太死，顾长林又急着证明自己的剑比你快。”</p><p>他将两柄短戟轻轻一碰：“我不会给你同样的机会。”</p><p>钟声落下，叶承已率先出手！</p><p>“唰——”</p><p>叶承第一步只跨出三尺，第二步却借短戟相撞的声响突然加速。两道漆黑戟光一高一低，高取肩颈，低封退路。陈玄看清了轨迹，身体却来不及完全避开。</p><p>陈玄瞳孔骤缩，青锋剑横挡胸前。</p><p>“铛！”</p><p>第一戟斩在剑身上，陈玄只觉一股巨力传来，整个人被震退三步，手臂发麻。</p><p>不等他站稳，第二戟已到！</p><p>“砰！”</p><p>戟背重重砸在陈玄胸口，虽然有剑气护体，但仍打得他呼吸一滞，胸口剧痛。</p><p>观战席上那个负责记录招式的弟子刚写下“第一戟”，台上已经响起第二次撞击。他停笔看了一眼，只得将那三个字划去重写。</p><p>陈玄强行稳住身形，青元剑气反切叶承手腕。但叶承似乎早有预料，短戟一转，护体灵力爆发，硬生生将剑气震散。</p><p>叶承低头看了一眼腕间尚未散去的青痕：“力道到了，剑气还差一层。”</p><p>话音未落，他再次欺身而上，双刃短戟如狂风暴雨般攻来。陈玄节节败退，左支右绌，身上的伤口越来越多。</p><p>三十息后，陈玄胸前已中了三记戟背，嘴角溢出血丝，呼吸急促。</p><p>六十息后，他的步法开始凌乱，剑势被彻底压制。</p><p>一百息后，叶承一戟横扫，陈玄横剑格挡，整个人被震得滑退到擂台边线，半只脚踩空，险些出界！</p><p>“你能打到这一步，已经不错。”叶承收戟而立，声音平静，“但前二的门，不是炼气七层能闯的。认输吧，省得受苦。”</p><p>高处没有人出声点评。叶承从起手至今没有一次多余追击，陈玄试出的每条路都被他收戟封回去。越懂行的人，越知道这种没有破绽的压制比一招重击更难处理。</p><p>陈玄抹去嘴角血迹，没有回话。</p><p>他没有去看观战台，也没有让四周的目光替自己做决定。</p><p>陈玄快速判断身体。右臂还能出一道完整剑气，左肩无法承受重击，丹田灵力剩下六成。赢面很小，却没有小到必须此刻认输。</p><p>“再试一轮。”</p><p>陈玄再次举起青锋剑，剑尖直指叶承。</p><p>叶承看了一眼他垂得更低的左肩，没有劝第二次：“好。”</p><p>他身形一闪，双刃短戟如毒蛇出洞，直取陈玄咽喉！</p><p>陈玄不闪不避，青元剑气全力爆发，迎着戟锋冲去！</p><p>“铛！铛！铛！”</p><p>金铁交鸣之声震耳欲聋，两人瞬间交手十余招。陈玄的剑很快，但叶承的戟更快；陈玄的剑很妙，但叶承的灵力更浑厚。</p><p>又过三招，叶承抓住陈玄肩伤未愈的破绽，一戟点在他胸前！</p><p>“砰！”</p><p>陈玄整个人倒飞而出，重重摔在擂台边缘，一口鲜血喷出。</p><p>裁判及时介入：“停！陈玄已失再战之力，叶承胜！”</p><p>“叶承胜，进入决赛！”</p><p>掌声从叶承收戟时响起，不算喧闹，却很整齐。叶承没有向看台致意，先俯身捡起陈玄脱手的青锋剑，连剑带鞘放在他右手边，免得医棚弟子抬人时踩到。</p><p>陈玄躺在地上，胸口剧烈起伏，眼前一阵阵发黑。这一场输得没有借口。</p><p>炼气七层对炼气九层，中间的差距清清楚楚。叶承没有轻敌，也没有给他可以放大的错误。陈玄撑过百息，看见了差距，却没能跨过去。</p><p>他多试的那一轮也并非全无所得。叶承护体灵光的确会在双戟交错时略薄，可那点薄弱短到不是目前的他能够利用。知道路在哪里，与走得到，是两回事。</p><hr><p>按赛制，陈玄将与另一名半决赛落败者争夺第三名。</p><p>医棚内，执事给他服下一枚回灵丹。药力化开后，丹田恢复三成灵力，伤口却仍在隐隐作痛。</p><p>陈玄闭目调息，把注意力从“败给叶承”的不甘，拉回到眼前这场必须拿下的战斗。</p><p>第三名，是他目前唯一的机会。</p><p>第三名决位战，对手赵无锋，炼气九层，枪修。</p><p>此人排名外门第四，枪法以杀伐著称，据说曾一枪斩杀二阶妖兽，实力不容小觑。</p><p>赵无锋同样不是全盛状态。他在另一场半决赛中败给秦岚，右肩被水火术灼伤，握枪手缠着厚厚药布。两人都只休整了一个时辰，这场争的不是谁毫发无伤，而是谁能在残余战力里少犯一次错。</p><p>赵无锋上台时，一杆玄铁长枪拖在身后，枪尖划过台面，火星一路飞溅。他右肩缠了三层药布，最外一层仍有水火术灼出的焦黄。握枪的手很稳，抬臂时肩头却比平日低了半寸。</p><p>“陈玄。”赵无锋声音低沉，“你那式青莲剑歌，我想见完整的。”</p><p>陈玄扶着医棚木柱起身，青锋剑横于胸前：“未必完整。”</p><p>赵无锋咧嘴一笑：“残招也行。我想看的是你怎么接。”</p><p>裁判敲钟：“开始！”</p><p>赵无锋没有试探，起手便是“裂风三枪”。他显然知道拖久了右肩先撑不住，于是把最重的三枪全压在开局，枪芒一层追一层，硬把陈玄逼向擂台东角。</p><p>“铛！铛！铛！铛！”</p><p>陈玄连格八次，每一次都震得他手臂发麻，虎口旧伤再次崩裂，鲜血染红剑柄。</p><p>“第一枪，破山！”</p><p>赵无锋一枪刺出，枪芒如虹，陈玄侧身闪避，枪芒擦着肩膀掠过，在地面留下一道尺深的裂痕。</p><p>“第二枪，断江！”</p><p>枪势横扫，陈玄举剑格挡，整个人被震得倒飞而出，撞在阵纹屏障上，胸口一闷，险些吐血。</p><p>“第三枪，裂风！”</p><p>赵无锋不给陈玄喘息之机，枪芒如狂风骤雨般罩下。</p><p>陈玄连挡带退，不去碰赵无锋右侧枪圈。他在等的也不是虚无缥缈的“盛极必衰”，而是那只受伤的肩膀什么时候无法继续把枪收回原位。</p><p>八十息。</p><p>九十息。</p><p>一百息。</p><p>赵无锋的枪势仍在加重，右肩药布却渐渐洇出一小块暗红。到了第一百一十息，他每次回枪，枪尾都会向下坠一寸。</p><p>第一百一十七息！</p><p>赵无锋一记“贯岳”直刺，灵力灌枪极深，枪芒暴涨，将陈玄身前退路尽数笼罩。</p><p>枪芒封死正面，枪尾回落时却多坠了半寸。</p><p>陈玄脚下一旋，沿枪杆内侧切入。他避不开最后那段反震，索性以右肩硬接，把左肩留给出剑。</p><p>“砰！”</p><p>胸口如遭重锤，闷响一声，陈玄几乎当场吐血，半边身子都麻了。</p><p>这一下撞得他喉间发甜，人却终于贴进长枪最难发力的内圈。</p><p>陈玄没有喊招，丹田余下灵力沿昨夜重新梳理的路线尽数涌入剑脊。青元三式首尾相扣，尚未完善的青莲剑歌在极近处展开。</p><p>“嗡——”</p><p>青光如莲瓣层层迭起。第一瓣斩在赵无锋右肩旧伤处，令护体灵光出现波纹；第二瓣不攻人，只压住长枪回撤路线；第三瓣才沿着灵光波纹直逼咽喉！</p><p>赵无锋瞳孔收缩，强提枪柄格挡，但仍被剑势压得连连后退。</p><p>一步、两步、三步……</p><p>第五步落下时，他脚跟已越过擂台白线！</p><p>出界！</p><p>裁判执事高喝：“陈玄胜，第三名！”</p><p>场边先有人喊了一声“五步”，随即更多声音跟着响起。负责界线的执事却没有立刻落锤，他蹲下身，用指尖在赵无锋脚跟处量过，确认鞋底确实越线，才把陈玄的名牌移进前三金栏。</p><p>金栏旁照例标着境界与来处：“炼气七层，药园。”几个同样穿灰衣的杂役弟子挤到榜墙前，看了好一会儿，其中一人伸手想摸那块牌子，又怕执事呵斥，半途缩了回去。</p><p>陈玄收剑站定，胸口剧烈起伏，眼前一阵发黑。</p><p>这一战，他拼尽了全力，经脉再次受创，却没有为了名次强行燃烧根基。最后一式仍有收束余地，这比昨日那次失控般的青莲变式更重要。</p><p>赵无锋走上前，看着陈玄苍白的脸色，抱拳道：“你赢得漂亮。那一剑，我心服口服。等你到炼气九层，再战一场。”</p><p>陈玄勉强扯出一个笑容：“好。”</p><hr><p>高台上，几位长老低声交谈。</p><p>黑袍长老道：“他把赵无锋的伤算进去了。”</p><p>灰袍老者摇头：“算进伤不难。难的是先前输给叶承后，他没急着用同一式证明自己，反而肯把第二瓣拿去压枪。”</p><p>一直没有开口的青衫中年放下茶盏：“还知道留一线收势。昨日那一剑是求胜，今日才有一点自己的意思。”</p><p>最终由执事长老宣读结果：</p><p>“本届内门大比前三为：第一叶承，第二秦岚，第三陈玄。前三皆获内门候选资格，并于明日入主殿受长老择徒。”</p><p>“择徒”二字落下，前排几名弟子不约而同望向高处长老席。前三只是取得入殿资格，哪一峰肯收、以亲传还是记名收，仍是另一场没有刀剑的选择。</p><p>陈玄抬头望向主殿。夕阳落在殿脊上，隔得很远，看不清门前究竟站着谁。他只把明日入殿的时辰记牢，又问执事能否先去医棚。</p><p>从青石村测灵落选到今日站进青云外门前三，他走了近三年，满身是伤，也终于走上第一道真正能被看见的台阶。</p><hr><p>傍晚散场时，天边晚霞如火。</p><p>陈玄独自回到后山石台，把青锋剑插在地上，坐了很久。</p><p>山风从药园方向过来，带着青须草晒过后的微苦气味。陈玄坐下不久便发现，自己习惯性挑的仍是那块背风石头，连青锋剑插入石缝的角度都与从前练剑时一样。</p><p>风吹过时，苏婉从观战台走下，在医棚外停了一步。</p><p>“青元第一重，你练成了。”她道。</p><p>陈玄想起白玉广场那次短暂交谈：“还差得远。”</p><p>“知道差得远，才走得下去。”苏婉看了一眼他重新渗血的右袖，“第三式转得太急。若赵无锋没有肩伤，你的第二瓣压不住他的枪。”</p><p>“我知道。”</p><p>“知道便好。”</p><p>她没有祝贺，也没有因陈玄进入前三便突然亲近，只留下这一句便转身离开。</p><p>陈玄望着白衣背影，唇角轻轻扬了一下。</p><p>这一次，他们谈的果然不再是四灵根能不能走到。</p><p>而是那一剑究竟错在哪里。</p><p>这还远远不够。</p><p>陈玄低头看了看右袖。苏婉说的那一处转折，正是布料重新渗血的地方。</p><p>他没有拔剑，只用两指隔着剑鞘，把第三式的回转慢慢比了一遍。做到一半，肩伤牵动，手便停在半空。</p><p>今日赢来的第三名已经写上榜墙，伤却不会因为那两个金字少疼一分。</p><p>陈玄收回手，先去医棚换药。</p><p>明日主殿，他得带着这些伤，去见那群决定他下一段路的人。</p><p>（第十八章完）</p>',129)])])}const m=e(r,[["render",o]]);export{h as __pageData,m as default};
